package com.example.demo.models;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDate;
@Entity @Table(name="perfiles_empleado") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class PerfilEmpleado{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@OneToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="persona_id",unique=true)private Persona persona;@Column(unique=true)private String legajo;private String puesto;@Column(name="fecha_contratacion")private LocalDate fechaContratacion;@Column(precision=14,scale=2)private BigDecimal sueldo;@Column(name="telefono_emergencia")private String telefonoEmergencia;private String observaciones;}
